using SiteInspector.Models;

namespace SiteInspector.Services;

public interface IInspectionStore
{
    ValueTask<List<Inspection>> GetAllInspectionsAsync();
    ValueTask<Inspection?> GetInspectionAsync(string id);
    ValueTask SaveInspectionAsync(Inspection inspection);
    ValueTask DeleteInspectionAsync(string id);
    ValueTask<List<Inspection>> GetPendingSyncAsync();
    ValueTask MarkSyncedAsync(string id);
}

using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Text.Json;

namespace SiteInspector.Services;

/// <summary>
/// IndexedDB-backed store for offline inspection data persistence.
/// </summary>
public class IndexedDbInspectionStore : IInspectionStore
{
    private readonly IJSRuntime _js;
    private bool _initialized;

    public IndexedDbInspectionStore(IJSRuntime js)
    {
        _js = js;
    }

    private async ValueTask EnsureInitializedAsync()
    {
        if (!_initialized)
        {
            await _js.InvokeVoidAsync("inspectionDb.initialize");
            _initialized = true;
        }
    }

    public async ValueTask<List<Inspection>> GetAllInspectionsAsync()
    {
        await EnsureInitializedAsync();
        return await _js.InvokeAsync<List<Inspection>>("inspectionDb.getAll") ?? new();
    }

    public async ValueTask<Inspection?> GetInspectionAsync(string id)
    {
        await EnsureInitializedAsync();
        return await _js.InvokeAsync<Inspection?>("inspectionDb.get", id);
    }

    public async ValueTask SaveInspectionAsync(Inspection inspection)
    {
        await EnsureInitializedAsync();
        await _js.InvokeVoidAsync("inspectionDb.save", inspection);
    }

    public async ValueTask DeleteInspectionAsync(string id)
    {
        await EnsureInitializedAsync();
        await _js.InvokeVoidAsync("inspectionDb.delete", id);
    }

    public async ValueTask<List<Inspection>> GetPendingSyncAsync()
    {
        await EnsureInitializedAsync();
        return await _js.InvokeAsync<List<Inspection>>("inspectionDb.getPending") ?? new();
    }

    public async ValueTask MarkSyncedAsync(string id)
    {
        await EnsureInitializedAsync();
        var inspection = await GetInspectionAsync(id);
        if (inspection != null)
        {
            inspection.SyncStatus = SyncStatus.Synced;
            await SaveInspectionAsync(inspection);
        }
    }
}

using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Net.Http.Json;

namespace SiteInspector.Services;

/// <summary>
/// Handles background sync of inspections when connectivity is available.
/// </summary>
public class SyncService : IDisposable
{
    private readonly IInspectionStore _store;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private Timer? _timer;
    private bool _isSyncing;

    public event Action<string>? OnSyncStatusChanged;
    public bool IsOnline { get; private set; } = true;

    public SyncService(IInspectionStore store, HttpClient http, IJSRuntime js)
    {
        _store = store;
        _http = http;
        _js = js;
    }

    public async Task StartAsync()
    {
        IsOnline = await _js.InvokeAsync<bool>("navigator.onLine.valueOf");
        await _js.InvokeVoidAsync("syncHelper.registerOnlineHandler",
            DotNetObjectReference.Create(this));
        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public void OnOnlineStatusChanged(bool isOnline)
    {
        IsOnline = isOnline;
        OnSyncStatusChanged?.Invoke(isOnline ? "Online" : "Offline");
        if (isOnline)
        {
            _ = TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing || !IsOnline) return;

        _isSyncing = true;
        try
        {
            var pending = await _store.GetPendingSyncAsync();
            foreach (var inspection in pending)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _store.MarkSyncedAsync(inspection.Id);
                        OnSyncStatusChanged?.Invoke($"Synced: {inspection.SiteName}");
                    }
                }
                catch
                {
                    // Sync will retry on next interval
                }
            }
        }
        finally
        {
            _isSyncing = false;
        }
    }

    public void Dispose()
    {
        _timer?.Dispose();
    }
}

