    </span>
</div>

<button class="btn-primary btn-large" @onclick="StartNewInspection">
    ➕ New Inspection
</button>

@if (_inspections == null)
{
    <p class="loading">Loading...</p>
}
else if (!_inspections.Any())
{
    <div class="empty-state">
        <p>No inspections yet.</p>
        <p>Tap "New Inspection" to get started.</p>
    </div>
}
else
{
    <div class="inspection-list">
        @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
        {
            <div class="inspection-card @GetStatusClass(inspection)" @onclick="() => OpenInspection(inspection.Id)">
                <div class="card-header">
                    <strong>@inspection.SiteName</strong>
                    <span class="sync-indicator @inspection.SyncStatus.ToString().ToLower()">
                        @GetSyncIcon(inspection.SyncStatus)
                    </span>
                </div>
                <div class="card-body">
                    <span>@inspection.CreatedAt.ToLocalTime().ToString("MMM dd, HH:mm")</span>
                    <span>@GetProgress(inspection)</span>
                </div>
            </div>
        }
