@page "/"
@using SiteInspector.Models
@using SiteInspector.Services
@inject IInspectionStore Store
@inject NavigationManager Nav
@inject SyncService Sync

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
    <span class="sync-badge @(Sync.IsOnline ? "online" : "offline")">
        @(Sync.IsOnline ? "● Online" : "● Offline")
    </span>
</div>

<button class="btn-primary btn-large" @onclick="StartNewInspection">
    ➕ New Inspection
</button>

@if (_inspections == null)
{
    <p class="loading">Loading...</p>
}
else if (!_inspections.Any())
{
    <div class="empty-state">
        <p>No inspections yet.</p>
        <p>Tap "New Inspection" to get started.</p>
    </div>
}
else
{
    <div class="inspection-list">
        @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
        {
            <div class="inspection-card @GetStatusClass(inspection)" @onclick="() => OpenInspection(inspection.Id)">
                <div class="card-header">
                    <strong>@inspection.SiteName</strong>
                    <span class="sync-indicator @inspection.SyncStatus.ToString().ToLower()">
                        @GetSyncIcon(inspection.SyncStatus)
                    </span>
                </div>
                <div class="card-body">
                    <span>@inspection.CreatedAt.ToLocalTime().ToString("MMM dd, HH:mm")</span>
                    <span>@GetProgress(inspection)</span>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Inspection>? _inspections;

    protected override async Task OnInitializedAsync()
    {
        _inspections = await Store.GetAllInspectionsAsync();
        Sync.OnSyncStatusChanged += _ => InvokeAsync(StateHasChanged);
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            ChecklistItems = ChecklistTemplates.GetStandardChecklist()
        };
        await Store.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private void OpenInspection(string id) => Nav.NavigateTo($"/inspection/{id}");

    private string GetProgress(Inspection i)
    {
        var done = i.ChecklistItems.Count(c => c.Result != CheckResult.NotInspected);
        return $"{done}/{i.ChecklistItems.Count} items";
    }

    private string GetStatusClass(Inspection i) =>
        i.CompletedAt.HasValue ? "completed" : "in-progress";

    private string GetSyncIcon(SyncStatus status) => status switch
    {
        SyncStatus.Synced => "✓",
        SyncStatus.Pending => "⏳",
        SyncStatus.Error => "⚠️",
        _ => ""
    };
}

@page "/inspection/{Id}"
@using SiteInspector.Models
@using SiteInspector.Services
@inject IInspectionStore Store
@inject NavigationManager Nav

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h2>Inspection</h2>
</div>

@if (_inspection == null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="inspection-form">
        <div class="form-group">
            <label>Site Name</label>
            <input type="text" @bind="_inspection.SiteName" @bind:event="oninput"
                   @onfocusout="Save" placeholder="Enter site name" />
        </div>
        <div class="form-group">
            <label>Inspector</label>
            <input type="text" @bind="_inspection.InspectorName" @bind:event="oninput"
                   @onfocusout="Save" placeholder="Your name" />
        </div>

        <div class="tab-bar">
            <button class="tab @(_activeTab == "checklist" ? "active" : "")"
                    @onclick='() => _activeTab = "checklist"'>Checklist</button>
            <button class="tab @(_activeTab == "photos" ? "active" : "")"
                    @onclick='() => _activeTab = "photos"'>Photos (@_inspection.Photos.Count)</button>
            <button class="tab @(_activeTab == "notes" ? "active" : "")"
                    @onclick='() => _activeTab = "notes"'>Notes</button>
        </div>

        @if (_activeTab == "checklist")
        {
            <div class="checklist-container">
                @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
                {
                    <div class="category-section">
                        <h3>@category.Key</h3>
                        @foreach (var item in category)
                        {
                            <div class="checklist-item @item.Result.ToString().ToLower()">
                                <div class="item-description">@item.Description</div>
                                <div class="item-actions">
                                    <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                                    <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                                    <button class="result-btn attention @(item.Result == CheckResult.NeedsAttention ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.NeedsAttention)">⚠</button>
                                </div>
                                @if (item.Result == CheckResult.Fail || item.Result == CheckResult.NeedsAttention)
                                {
                                    <input type="text" class="item-note" placeholder="Add note..."
                                           @bind="item.Notes" @bind:event="oninput" @onfocusout="Save" />
                                }
                            </div>
                        }
                    </div>
                }
            </div>
        }
        else if (_activeTab == "photos")
        {
            <div class="photos-container">
                <label class="btn-primary photo-capture-btn">
                    📷 Take Photo
                    <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment"
                               style="display:none" />
                </label>

                @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                {
                    <div class="photo-card">
                        <img src="@photo.DataUrl" alt="@photo.Caption" loading="lazy" />
                        <input type="text" placeholder="Add caption..." @bind="photo.Caption"
                               @bind:event="oninput" @onfocusout="Save" />
                        <button class="btn-danger-small" @onclick="() => RemovePhoto(photo)">Remove</button>
                    </div>
                }

                @if (!_inspection.Photos.Any())
                {
                    <p class="empty-state">No photos attached yet.</p>
                }
            </div>
        }
        else if (_activeTab == "notes")
        {
            <div class="notes-container">
                <textarea @bind="_inspection.Notes" @bind:event="oninput" @onfocusout="Save"
                          placeholder="General inspection notes..." rows="10"></textarea>
            </div>
        }

        <div class="form-actions">
            @if (!_inspection.CompletedAt.HasValue)
            {
                <button class="btn-primary btn-large" @onclick="CompleteInspection">
                    ✅ Complete Inspection
                </button>
            }
            else
            {
                <p class="completed-badge">Completed @_inspection.CompletedAt.Value.ToLocalTime().ToString("MMM dd, HH:mm")</p>
            }
        </div>
    </div>
}

