// IndexedDB operations for offline inspection storage
const DB_NAME = 'SiteInspectorDb';
const DB_VERSION = 1;
const STORE_NAME = 'inspections';

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains(STORE_NAME)) {
                const store = database.createObjectStore(STORE_NAME, { keyPath: 'id' });
                store.createIndex('syncStatus', 'syncStatus', { unique: false });
                store.createIndex('createdAt', 'createdAt', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.inspectionDb = {
    initialize: async () => { await openDb(); },

    getAll: async () => {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const store = tx.objectStore(STORE_NAME);
            const request = store.getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = () => reject(request.error);
        });
    },

    get: async (id) => {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const store = tx.objectStore(STORE_NAME);
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = () => reject(request.error);
        });
    },

    save: async (inspection) => {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readwrite');
            const store = tx.objectStore(STORE_NAME);
            const request = store.put(inspection);
            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    },

    delete: async (id) => {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readwrite');
            const store = tx.objectStore(STORE_NAME);
            const request = store.delete(id);
            request.onsuccess = () => resolve();
            request.onerror = () => reject(request.error);
        });
    },

    getPending: async () => {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(STORE_NAME, 'readonly');
            const store = tx.objectStore(STORE_NAME);
            const index = store.index('syncStatus');
            // SyncStatus.Pending = 0
            const request = index.getAll(0);
            request.onsuccess = () => resolve(request.result);
            request.onerror = () => reject(request.error);
        });
    }
};

// Online/offline status helper
window.syncHelper = {
    registerOnlineHandler: (dotNetRef) => {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnOnlineStatusChanged', true));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnOnlineStatusChanged', false));
    }
};

